// Validate the client preview engine (preview.js) against the server engine's
// results: runs build/preview-fixtures.json (generated by PreviewFixtureGenerator,
// using ScoringEngine.preview as the oracle) and asserts preview.js matches.
// Run: node tools/preview-validate.cjs  (after `gradlew test` generates the fixtures)
const fs = require('fs');
const path = require('path');

const { BalatroPreview } = require(path.join(__dirname, '..', 'src', 'main', 'resources', 'public', 'preview.js'));
const fixtures = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'build', 'preview-fixtures.json'), 'utf8'));

const close = (a, b) => Math.abs(a - b) <= 1e-6 * Math.max(1, Math.abs(a), Math.abs(b));
let failures = 0;

for (const fx of fixtures) {
  const got = BalatroPreview.previewScore(fx.played, fx.held, fx.jokers, fx.run);
  const exp = fx.expected;
  if (!got) {
    console.log(`FAIL ${fx.name}: client returned null (unsupported) but server scored ${exp.score}`);
    failures++;
    continue;
  }
  const ok = close(got.chips, exp.chips) && close(got.mult, exp.mult) && close(got.score, exp.score);
  if (ok) {
    console.log(`ok   ${fx.name}: ${got.chips} x ${got.mult} = ${got.score}`);
  } else {
    console.log(`FAIL ${fx.name}: client ${got.chips} x ${got.mult} = ${got.score}` +
      ` | server ${exp.chips} x ${exp.mult} = ${exp.score}`);
    failures++;
  }
}

console.log(`\n${fixtures.length - failures}/${fixtures.length} scenarios match`);
process.exit(failures === 0 ? 0 : 1);
